#include <iostream>
#include <string>
#include <vector>
#include <sstream>
#include <fstream>
#include <cstdio> // For remove
#include <cstdlib> // For system

// This driver assumes the student's code is compiled into an executable named 'solution'.
// On Linux/macOS, compile with: g++ <your_code>.cpp -o solution
// On Windows, compile with: g++ <your_code>.cpp -o solution.exe

// The driver will write input to a temporary file, run the solution with redirected I/O,
// and then read the output from another temporary file for comparison.

int main() {
    std::vector<std::pair<std::string, std::string>> test_cases = {
        {"1 2 3 4 5 6 7 8", "4.50"},
        {"10 20 30 40 50 60 70 80", "45.00"}
    };

    std::string executable_name = "./solution"; // Adjust for Windows if necessary: "solution.exe"

    for (size_t i = 0; i < test_cases.size(); ++i) {
        const std::string& input_str = test_cases[i].first;
        const std::string& expected_output = test_cases[i].second;
        std::string actual_output;

        // Write input to a temporary file
        std::ofstream input_file("input.txt");
        input_file << input_str;
        input_file.close();

        // Command to run the student's solution with input/output redirection
        std::string command = executable_name + " < input.txt > output.txt";

        // Execute the command
        int system_result = system(command.c_str());

        // Read output from the temporary file
        std::ifstream output_file("output.txt");
        if (output_file.is_open()) {
            std::stringstream buffer;
            buffer << output_file.rdbuf();
            actual_output = buffer.str();
            // Remove trailing newline for consistent comparison
            if (!actual_output.empty() && actual_output.back() == '\n') {
                actual_output.pop_back();
            }
            output_file.close();
        } else {
            actual_output = "ERROR: Could not read output file.\n";
        }

        std::cout << "Test Case " << (i + 1) << ":\n";
        std::cout << "Input: " << input_str << "\n";
        std::cout << "Expected: " << expected_output << "\n";
        std::cout << "Actual: " << actual_output << "\n";

        // For syntax errors, the program might not even produce output or crash
        if (system_result != 0) {
            std::cout << "Result: Program crashed or failed to execute (Exit Code: " << system_result << ")\n";
        } else if (actual_output == expected_output) {
            std::cout << "Result: PASSED\n";
        } else {
            std::cout << "Result: FAILED\n";
        }
        std::cout << "----------------------------------------\n";

        // Clean up temporary files
        remove("input.txt");
        remove("output.txt");
    }

    return 0;
}
